INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-7c9828ae-moex-00026', 'aboriginal-7c9828ae', 'aboriginal-7c9828ae-moex-114-3082b5f1', 'sub-aboriginal-7c9828ae-04', NULL, 'single_choice', '行政處分於法定救濟期間經過後，相對人或利害關係人得依規定向行政機關申請撤銷、廢止或變 更之。下列敘述何者錯誤？', '["相對人因重大過失而未能在行政程序或救濟程序中主張其事由者，得申請撤銷之", "具有持續效力之行政處分所依據之事實事後發生有利於相對人或利害關係人之變更者，得申請 廢止之", "發生新事實或發現新證據者，但以如經斟酌可受較有利益之處分者為限，相對人得申請變更之", "具有相當於行政訴訟法所定再審事由且足以影響行政處分者，相對人或利害關係人得申請撤銷之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:54+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "503", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會工作"}'::jsonb, NULL),
  ('aboriginal-7c9828ae-moex-00027', 'aboriginal-7c9828ae', 'aboriginal-7c9828ae-moex-114-3082b5f1', 'sub-aboriginal-7c9828ae-04', NULL, 'single_choice', '依司法實務見解，關於行政契約之敘述，下列何者錯誤？', '["土地徵收前，需用土地人與人民依協議價購方式取得私人土地之契約，為行政契約", "行政契約與私法契約之區別，原則上以契約標的為準，若契約標的給付行為不易區分為公、私 法性質，則須就契約目的及契約整體特徵作判斷", "公立大學與教師之關係為行政契約關係，學校對教師所為之不續聘非屬行政契約上之意思表示", "教育部與醫學院公費生約定，公費生於服務未期滿前，由分發機關代為保管其專業證書，為行 政契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:54+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "503", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會工作"}'::jsonb, NULL),
  ('aboriginal-7c9828ae-moex-00028', 'aboriginal-7c9828ae', 'aboriginal-7c9828ae-moex-114-3082b5f1', 'sub-aboriginal-7c9828ae-04', NULL, 'single_choice', '下列何者非屬行政指導？', '["市政府函請市民甲於颱風即將來臨前作好水土保持", "縣政府社會局函請社會救助申請人乙於一定期間內提供補正資料", "區公所履勘現有巷道時，勸說巷道土地所有權人丙自行移除路障", "金融監督管理委員會函請丁金融機構切實遵守法令並協助防範金融詐騙事件 50750、51050"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:54+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "503", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會工作"}'::jsonb, NULL),
  ('aboriginal-7c9828ae-moex-00029', 'aboriginal-7c9828ae', 'aboriginal-7c9828ae-moex-114-3082b5f1', 'sub-aboriginal-7c9828ae-04', NULL, 'single_choice', '直轄市環保局公務員甲發現市民乙正在噪音管制區內進行營建工程，發出巨大聲響，現場測得超 過噪音管制標準，該公務員不得即時作何種處置？', '["即時制止發出噪音之行為", "要求行為人出示身分證件，以確認違法行為人身分", "對於拒絕配合身分查驗之行為人，自力逮捕並帶往留置處所", "製作書面紀錄，以利行政罰之進行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:54+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "503", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會工作"}'::jsonb, NULL),
  ('aboriginal-7c9828ae-moex-00030', 'aboriginal-7c9828ae', 'aboriginal-7c9828ae-moex-114-3082b5f1', 'sub-aboriginal-7c9828ae-04', NULL, 'single_choice', '行政執行法有關拘提與管收之規定，下列敘述何者錯誤？', '["拘提與管收僅適用於公法上金錢給付義務未履行的情形", "債務人未依期限履行債務亦未提供相當擔保，而有逃匿之虞時，應先聲請拘提，不得逕行管收", "拘提無須向法院聲請裁定，但管收須向法院聲請裁定", "行政執行機關如認為有將債務人管收之必要者，須自拘提時起24小時內，聲請法院裁定管收"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:54+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "503", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會工作"}'::jsonb, NULL),
  ('aboriginal-7c9828ae-moex-00031', 'aboriginal-7c9828ae', 'aboriginal-7c9828ae-moex-114-3082b5f1', 'sub-aboriginal-7c9828ae-04', NULL, 'single_choice', '主管機關命甲履行某行政法上行為義務，並諭知若逾期未履行，將委託第三人依行政執行法規定 代為履行，其費用由甲負擔。甲逾期未履行該義務，主管機關即委託第三人代履行後，通知甲限 期繳納代履行費用。甲逾期未繳納，主管機關得為如何處理？', '["作成行政處分，限期命甲支付代履行費用", "提起一般給付訴訟，請求判命甲支付代履行費用", "移送法務部行政執行署所屬行政執行分署強制執行", "代位行使第三人之請求權，向民事法院提起給付訴訟，請求判命甲給付費用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:54+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "503", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會工作"}'::jsonb, NULL),
  ('aboriginal-7c9828ae-moex-00032', 'aboriginal-7c9828ae', 'aboriginal-7c9828ae-moex-114-3082b5f1', 'sub-aboriginal-7c9828ae-04', NULL, 'single_choice', '下列何者非相當於訴願決定？', '["教師申訴評議委員會之再申訴決定", "會計師懲戒覆審委員會之決議", "公務人員保障暨培訓委員會之復審決定", "律師懲戒覆審委員會之決議"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:54+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "503", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會工作"}'::jsonb, NULL),
  ('aboriginal-7c9828ae-moex-00033', 'aboriginal-7c9828ae', 'aboriginal-7c9828ae-moex-114-3082b5f1', 'sub-aboriginal-7c9828ae-04', NULL, 'single_choice', '關於撤銷原處分之訴願決定，其拘束力範圍，下列敘述何者正確？', '["僅訴願決定之法律見解對原處分機關有拘束力", "僅訴願決定之事實認定對原處分機關有拘束力", "訴願決定之法律見解與事實認定均對原處分機關有拘束力", "訴願決定對原處分機關不具拘束力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:54+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "503", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會工作"}'::jsonb, NULL),
  ('aboriginal-7c9828ae-moex-00034', 'aboriginal-7c9828ae', 'aboriginal-7c9828ae-moex-114-3082b5f1', 'sub-aboriginal-7c9828ae-04', NULL, 'single_choice', '關於都市計畫審查訴訟之敘述，下列何者正確？', '["都市計畫審查訴訟，專屬都市計畫區所在地之高等行政法院地方行政訴訟庭管轄", "得提起都市計畫審查訴訟者，以其權利受行政機關發布之違法都市計畫損害之人民為限", "都市計畫審查訴訟，原則上應於行政機關發布都市計畫後1年之不變期間內提起", "管轄之行政法院認為系爭都市計畫為違法者，原則上應作成宣告違法並向將來失效之形成判決"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:54+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "503", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會工作"}'::jsonb, NULL),
  ('aboriginal-7c9828ae-moex-00035', 'aboriginal-7c9828ae', 'aboriginal-7c9828ae-moex-114-3082b5f1', 'sub-aboriginal-7c9828ae-04', NULL, 'single_choice', '公平交易委員會審查化工事業甲與乙之結合案，雖作出不禁止決定，但附加負擔「應自結合起 5 年內每年執行動物保護慈善公益活動並提交報告」，甲僅對此附款不服，訴願未果後，應提起何種 訴訟？', '["撤銷訴訟", "一般給付之訴", "確認法律關係不存在之訴", "確認行政處分違法之訴"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:54+00:00", "source_pdf_sha1": "bf7be7405e55", "answer_pdf_sha1": "2e88d7bce4a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "503", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "社會工作"}'::jsonb, NULL)
